function Notification({ messages }) {
  if (!messages.length) {
    return <p>No messages</p>;
  }

  // If we reach here, there are messages
  return (
    <ul>
      {messages.map(msg => <li key={msg.id}>{msg.text}</li>)}
    </ul>
  );
}
